/* This simple program demonstrates:
   1. Including standard library
   2. Main function declaration
   3. Basic output using printf
   4. Return statement */

#include <stdio.h>

int main() {
    // Variable declarations
    int age = 25;
    float height = 5.9;
    char grade = 'A';
    double pi = 3.14159;

    // Printing variables
    printf("Age: %d\n", age);
    printf("Height: %.1f\n", height);
    printf("Grade: %c\n", grade);
    printf("Pi: %f\n", pi);

    return 0;
}

#include <stdio.h>

int main() {
    int score = 85;

    // if-else example
    if (score >= 90) {
        printf("Grade: A\n");
    } else if (score >= 80) {
        printf("Grade: B\n");
    } else {
        printf("Grade: C\n");
    }

    // switch example
    switch (score / 10) {
        case 10:
        case 9:
            printf("Excellent!\n");
            break;
        case 8:
            printf("Good!\n");
            break;
        default:
            printf("Keep trying!\n");
    }

    return 0;
}
